import Contact from "./Contact";
import Gallery from "./Gallery";
import Portfolio from "./Portfolio";
import Home from "./Home";
import Error from "./Error";

export interface Page {
    name: string
    element: React.ReactNode;
}

const Pages: Page[] = [
    {
        name: 'Contact',
        element: <Contact/>
    },
    {
        name: 'Gallery',
        element: <Gallery/>
    },
    {
        name: 'Portfolio',
        element: <Portfolio/>
    },
    {
        name: 'Home',
        element: <Home/>
    },
    {
        name: '*',
        element: <Error/>
    },
]

export default Pages;
